import{_ as a,c as n,o as e,a7 as s}from"./chunks/framework.BQb8NfN9.js";const c=JSON.parse('{"title":"卷积神经网络（CNN）","description":"","frontmatter":{},"headers":[],"relativePath":"ai/深度学习/卷积神经网络.md","filePath":"ai/深度学习/卷积神经网络.md","lastUpdated":1773670517000}'),d={name:"ai/深度学习/卷积神经网络.md"};function r(l,t,i,o,p,h){return e(),n("div",null,t[0]||(t[0]=[s(`<h1 id="卷积神经网络-cnn" tabindex="-1">卷积神经网络（CNN） <a class="header-anchor" href="#卷积神经网络-cnn" aria-label="Permalink to &quot;卷积神经网络（CNN）&quot;">​</a></h1><p>卷积神经网络（Convolutional Neural Network，CNN）是专门为处理<strong>网格状数据</strong>（如图像、视频、音频频谱）设计的深度神经网络，凭借局部感知和参数共享两大核心思想，大幅降低参数量并提升平移不变性，是计算机视觉领域的基石。</p><p><strong>文档结构：</strong> 核心思想 → 网络整体结构 → 卷积层（核心计算）→ 激活层 → 池化层 → 全连接层 → 经典网络架构 → 知识小结。</p><hr><h2 id="一、核心思想" tabindex="-1">一、核心思想 <a class="header-anchor" href="#一、核心思想" aria-label="Permalink to &quot;一、核心思想&quot;">​</a></h2><h3 id="局部感知-local-receptive-field" tabindex="-1">局部感知（Local Receptive Field） <a class="header-anchor" href="#局部感知-local-receptive-field" aria-label="Permalink to &quot;局部感知（Local Receptive Field）&quot;">​</a></h3><p>全连接网络中每个神经元连接所有输入像素，对于 $224\\times224$ 的图像参数量极大。CNN 中每个神经元只感知<strong>一小块局部区域</strong>（感受野），通过堆叠多层来逐步扩大感受野，学习从低级到高级的特征。</p><h3 id="参数共享-weight-sharing" tabindex="-1">参数共享（Weight Sharing） <a class="header-anchor" href="#参数共享-weight-sharing" aria-label="Permalink to &quot;参数共享（Weight Sharing）&quot;">​</a></h3><p>同一个卷积核在整张图像上<strong>滑动使用相同参数</strong>，检测同一类特征（如边缘）不论出现在图像哪个位置。这使参数量从 $H \\times W \\times C_{in} \\times C_{out}$ 降低到 $k \\times k \\times C_{in} \\times C_{out}$。</p><h3 id="平移不变性" tabindex="-1">平移不变性 <a class="header-anchor" href="#平移不变性" aria-label="Permalink to &quot;平移不变性&quot;">​</a></h3><p>由于参数共享，同一特征无论位置如何平移，卷积核都能将其检测到，使 CNN 对目标位置不敏感。</p><hr><h2 id="二、整体网络结构" tabindex="-1">二、整体网络结构 <a class="header-anchor" href="#二、整体网络结构" aria-label="Permalink to &quot;二、整体网络结构&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入图像</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>[卷积层 Conv] → 提取局部特征</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>[激活层 ReLU] → 引入非线性</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>[池化层 Pool] → 降维 + 增大感受野</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>（上述三层可重复多次）</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>[展平 Flatten]</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>[全连接层 FC] → 综合特征，分类/回归</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>输出（Softmax）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><table tabindex="0"><thead><tr><th>层类型</th><th>作用</th><th>典型参数</th></tr></thead><tbody><tr><td>卷积层 Conv</td><td>提取局部空间特征</td><td>卷积核大小 $k$、步长 $s$、填充 $p$、通道数 $C_{out}$</td></tr><tr><td>激活层 ReLU</td><td>引入非线性</td><td>无参数</td></tr><tr><td>池化层 Pool</td><td>降维，增强平移不变性</td><td>核大小、步长，最大/平均池化</td></tr><tr><td>全连接层 FC</td><td>综合特征，输出分类结果</td><td>输出维度</td></tr></tbody></table><hr><h2 id="三、卷积层" tabindex="-1">三、卷积层 <a class="header-anchor" href="#三、卷积层" aria-label="Permalink to &quot;三、卷积层&quot;">​</a></h2><h3 id="卷积核-filter-kernel" tabindex="-1">卷积核（Filter / Kernel） <a class="header-anchor" href="#卷积核-filter-kernel" aria-label="Permalink to &quot;卷积核（Filter / Kernel）&quot;">​</a></h3><p>卷积核是一个小矩阵（如 $3\\times3$），包含可学习的权重参数。<strong>一个卷积核提取一种特征</strong>（如水平边缘），多个卷积核提取多种特征，输出多个特征图（Feature Map）。</p><h3 id="单卷积核计算-2d-卷积" tabindex="-1">单卷积核计算（2D 卷积） <a class="header-anchor" href="#单卷积核计算-2d-卷积" aria-label="Permalink to &quot;单卷积核计算（2D 卷积）&quot;">​</a></h3><p>对于输入特征图 $X$（$H \\times W$）和卷积核 $K$（$k \\times k$），在位置 $(i, j)$ 处的输出为：</p><p>$$O(i, j) = \\sum_{m=0}^{k-1}\\sum_{n=0}^{k-1} X(i \\cdot s + m,\\ j \\cdot s + n) \\cdot K(m, n) + b$$</p><p>其中 $s$ 为步长（stride），$b$ 为偏置。</p><p><strong>示例（$3\\times3$ 核在 $5\\times5$ 输入上滑动，步长 1，无填充）：</strong></p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入（5×5）          卷积核（3×3）       输出（3×3）</span></span>
<span class="line"><span>1 0 1 0 1           1  0  1           </span></span>
<span class="line"><span>0 1 0 1 0   ✕       0  1  0    =  特征图（3×3）</span></span>
<span class="line"><span>1 0 1 0 1           1  0  1</span></span>
<span class="line"><span>0 1 0 1 0</span></span>
<span class="line"><span>1 0 1 0 1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="输出尺寸计算" tabindex="-1">输出尺寸计算 <a class="header-anchor" href="#输出尺寸计算" aria-label="Permalink to &quot;输出尺寸计算&quot;">​</a></h3><p>$$H_{out} = \\left\\lfloor \\frac{H_{in} - k + 2p}{s} \\right\\rfloor + 1$$</p><p>$$W_{out} = \\left\\lfloor \\frac{W_{in} - k + 2p}{s} \\right\\rfloor + 1$$</p><p>其中：</p><ul><li>$k$：卷积核大小</li><li>$p$：填充（padding）大小</li><li>$s$：步长（stride）</li></ul><p><strong>常见设置（保持尺寸不变）：</strong> $k=3, p=1, s=1$ → $H_{out} = H_{in}$</p><h3 id="多通道卷积" tabindex="-1">多通道卷积 <a class="header-anchor" href="#多通道卷积" aria-label="Permalink to &quot;多通道卷积&quot;">​</a></h3><p>对 RGB 图像（$C_{in}=3$），每个卷积核扩展为 $k \\times k \\times C_{in}$，在三个通道分别卷积后求和。$N$ 个卷积核输出 $N$ 个特征图，即 $C_{out} = N$。</p><p>$$\\text{参数量} = k \\times k \\times C_{in} \\times C_{out} + C_{out}\\ \\text{（偏置）}$$</p><h3 id="填充-padding" tabindex="-1">填充（Padding） <a class="header-anchor" href="#填充-padding" aria-label="Permalink to &quot;填充（Padding）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>填充方式</th><th>说明</th><th>效果</th></tr></thead><tbody><tr><td>无填充（Valid）</td><td>$p=0$，输出尺寸缩小</td><td>丢失边缘信息</td></tr><tr><td>零填充（Same）</td><td>$p=(k-1)/2$，输出与输入等尺寸</td><td>保留边缘信息，最常用</td></tr></tbody></table><hr><h2 id="四、激活层" tabindex="-1">四、激活层 <a class="header-anchor" href="#四、激活层" aria-label="Permalink to &quot;四、激活层&quot;">​</a></h2><p>卷积后通常紧跟激活函数（不单独算一层，但逻辑上独立）。</p><p><strong>首选 ReLU：</strong> $f(z) = \\max(0, z)$</p><ul><li>计算快，正区间梯度为 1，缓解梯度消失。</li><li>在 CNN 中几乎是默认选择。</li></ul><hr><h2 id="五、池化层" tabindex="-1">五、池化层 <a class="header-anchor" href="#五、池化层" aria-label="Permalink to &quot;五、池化层&quot;">​</a></h2><p>池化（Pooling）对特征图进行降采样，减小空间尺寸，降低计算量，同时增强特征对微小平移的鲁棒性。</p><h3 id="最大池化-max-pooling" tabindex="-1">最大池化（Max Pooling） <a class="header-anchor" href="#最大池化-max-pooling" aria-label="Permalink to &quot;最大池化（Max Pooling）&quot;">​</a></h3><p>$$O(i, j) = \\max_{m,n \\in \\text{窗口}} X(i \\cdot s + m,\\ j \\cdot s + n)$$</p><p>取窗口内的最大值，<strong>保留最显著特征</strong>，最常用（如 $2\\times2$, stride=2，尺寸减半）。</p><h3 id="平均池化-average-pooling" tabindex="-1">平均池化（Average Pooling） <a class="header-anchor" href="#平均池化-average-pooling" aria-label="Permalink to &quot;平均池化（Average Pooling）&quot;">​</a></h3><p>取窗口内的平均值，特征更平滑，多用于网络末端（Global Average Pooling，GAP）替代全连接层以减少参数。</p><h3 id="池化参数对比" tabindex="-1">池化参数对比 <a class="header-anchor" href="#池化参数对比" aria-label="Permalink to &quot;池化参数对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>典型值</th><th>说明</th></tr></thead><tbody><tr><td>核大小</td><td>$2\\times2$</td><td>常用</td></tr><tr><td>步长</td><td>2</td><td>尺寸减半</td></tr><tr><td>类型</td><td>Max / Avg</td><td>Max 更常用</td></tr></tbody></table><p><strong>池化层无可学习参数</strong>，只做降采样运算。</p><hr><h2 id="六、全连接层" tabindex="-1">六、全连接层 <a class="header-anchor" href="#六、全连接层" aria-label="Permalink to &quot;六、全连接层&quot;">​</a></h2><p>经过若干卷积 + 池化后，将三维特征图展平（Flatten）为一维向量，送入全连接层：</p><p>$$\\boldsymbol{z} = \\boldsymbol{W}\\boldsymbol{h} + \\boldsymbol{b}$$</p><ul><li><strong>作用</strong>：综合所有空间位置的高级特征，进行最终分类或回归。</li><li><strong>问题</strong>：参数量大（占整个网络参数的绝大部分）。</li><li><strong>现代趋势</strong>：用 Global Average Pooling（GAP）替代全连接，大幅减少参数，减轻过拟合。</li></ul><hr><h2 id="七、经典网络架构" tabindex="-1">七、经典网络架构 <a class="header-anchor" href="#七、经典网络架构" aria-label="Permalink to &quot;七、经典网络架构&quot;">​</a></h2><table tabindex="0"><thead><tr><th>网络</th><th>年份</th><th>核心贡献</th><th>层数</th></tr></thead><tbody><tr><td>LeNet-5</td><td>1998</td><td>开创 CNN 用于手写识别</td><td>7 层</td></tr><tr><td>AlexNet</td><td>2012</td><td>深度 CNN + ReLU + Dropout + GPU，ImageNet 冠军</td><td>8 层</td></tr><tr><td>VGGNet</td><td>2014</td><td>纯堆叠 $3\\times3$ 小卷积核，结构简洁</td><td>16/19 层</td></tr><tr><td>GoogLeNet</td><td>2014</td><td>Inception 模块，多尺度并行卷积</td><td>22 层</td></tr><tr><td>ResNet</td><td>2015</td><td>残差连接（Skip Connection），解决梯度消失，突破百层</td><td>50/101/152 层</td></tr></tbody></table><h3 id="残差连接-resnet-核心" tabindex="-1">残差连接（ResNet 核心） <a class="header-anchor" href="#残差连接-resnet-核心" aria-label="Permalink to &quot;残差连接（ResNet 核心）&quot;">​</a></h3><p>$$\\boldsymbol{y} = F(\\boldsymbol{x}) + \\boldsymbol{x}$$</p><p>将输入 $\\boldsymbol{x}$ 直接跳过若干层加到输出，梯度可沿短路径直接流回，解决深层网络退化问题。</p><hr><h2 id="八、知识小结" tabindex="-1">八、知识小结 <a class="header-anchor" href="#八、知识小结" aria-label="Permalink to &quot;八、知识小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识点</th><th>核心内容</th><th>易混淆点</th><th>难度</th></tr></thead><tbody><tr><td>核心思想</td><td>局部感知 + 参数共享 → 减少参数、平移不变</td><td>与全连接的区别</td><td>⭐⭐</td></tr><tr><td>卷积计算</td><td>核在输入上滑动，加权求和 + 偏置</td><td>步长和填充对输出尺寸的影响</td><td>⭐⭐⭐</td></tr><tr><td>输出尺寸公式</td><td>$H_{out}=\\lfloor(H_{in}-k+2p)/s\\rfloor+1$</td><td>Same padding 时 $p=(k-1)/2$</td><td>⭐⭐⭐</td></tr><tr><td>多通道卷积</td><td>核扩展为 $k \\times k \\times C_{in}$，$N$ 个核→$C_{out}=N$</td><td>参数量计算</td><td>⭐⭐⭐</td></tr><tr><td>池化层</td><td>降采样，Max 保留最强激活，无可学习参数</td><td>池化 vs 卷积（有无参数）</td><td>⭐⭐</td></tr><tr><td>全连接层</td><td>展平后综合特征；参数量大，现代常用 GAP 替代</td><td>Flatten 操作</td><td>⭐⭐</td></tr><tr><td>残差连接</td><td>$y=F(x)+x$，梯度短路，解决深层退化</td><td>ResNet 解决的问题</td><td>⭐⭐⭐</td></tr></tbody></table>`,66)]))}const $=a(d,[["render",r]]);export{c as __pageData,$ as default};
